function report = runGpuHeightSweepBenchmark(options)
%RUNGPUHEIGHTSWEEPBENCHMARK Benchmark exact ZNCC plus SGM array execution.
%
% This public G1.3 harness renders one deterministic pinhole pair, keeps
% camera geometry in CPU double, and runs the selected array target through
% exact ZNCC and physical-height SGM. CompareCpu evaluates the established
% optimized CPU path under identical labels, masks, costs, and penalties.
%
% Example on supported Windows/NVIDIA hardware:
%   report = runGpuHeightSweepBenchmark;
%
% Hardware-independent control on macOS:
%   report = runGpuHeightSweepBenchmark(ExecutionTarget="cpu-array");
%
% Traceability: algo/main.tex Algorithm 1 and Eqs. (68)--(75);
% docs/implementation_plan.md G1.3--G1.4.

arguments
    options.ExecutionTarget (1, 1) string ...
        {mustBeMember(options.ExecutionTarget, ...
        ["gpu", "cpu-array"])} = "gpu"
    options.DeviceIndex (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.ImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, ...
        mustBeGreaterThanOrEqual(options.ImageSize, 16)} = [512, 512]
    options.HeightRangeMetres (1, 2) double ...
        {mustBeFinite, mustBeIncreasing} = [-25, 25]
    options.LabelCount (1, 1) double ...
        {mustBeFinite, mustBeInteger, ...
        mustBeGreaterThanOrEqual(options.LabelCount, 3)} = 21
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [128, 128]
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 4
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ...
        ["single", "double"])} = "single"
    options.DirectionCount (1, 1) double ...
        {mustBeMember(options.DirectionCount, [4, 8])} = 8
    options.PenaltyPerMetre (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 0.02
    options.MaximumPenalty (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 0.2
    options.MinimumSupportFraction (1, 1) double ...
        {mustBeFinite, ...
        mustBeGreaterThanOrEqual(options.MinimumSupportFraction, 0), ...
        mustBeLessThanOrEqual(options.MinimumSupportFraction, 1)} = 0.8
    options.TextureSeed (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 20260719
    options.CompareCpu (1, 1) logical = true
    options.StoreCostVolumes (1, 1) logical = false
    options.CostTolerance (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 3e-5
    options.TieTolerance (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 1e-4
    options.Verbose (1, 1) logical = true
    options.OutputFile (1, 1) string = ""
end

z = linspace(options.HeightRangeMetres(1), ...
    options.HeightRangeMetres(2), options.LabelCount);
renderTimer = tic;
renderer = SyntheticPinholeRenderer("gpu-g1-benchmark", ...
    options.ImageSize, Supersample=2, PsfSigmaPixels=0.5, ...
    TextureSeed=options.TextureSeed);
pair = renderer.renderPair;
renderSeconds = toc(renderTimer);

prepareTimer = tic;
g = HeightSweepGeometry( ...
    renderer.ReferenceCamera, renderer.MovingCamera);
levels = 2 ^ renderer.BitDepth - 1;
r = cast(pair.ReferenceImage, options.WorkingPrecision) ...
    ./ cast(levels, options.WorkingPrecision);
m = cast(pair.MovingImage, options.WorkingPrecision) ...
    ./ cast(levels, options.WorkingPrecision);
c = HeightCostCurve(g, r, m, ...
    DerivativeSigma=1, IntegrationSigma=1, ...
    ReferenceValid=pair.ReferenceValid, ...
    MovingValid=pair.MovingValid, PrepareGradients=false, ...
    WorkingPrecision=options.WorkingPrecision);
d = DenseHeightSweep(c);
prepareSeconds = toc(prepareTimer);

needVolumes = options.StoreCostVolumes || options.CompareCpu;
q = GpuHeightSweep.runZnccSgm(d, z, ...
    ExecutionTarget=options.ExecutionTarget, ...
    DeviceIndex=options.DeviceIndex, TileSize=options.TileSize, ...
    LabelBlockSize=options.LabelBlockSize, ...
    WorkingPrecision=options.WorkingPrecision, ...
    StoreCostVolumes=needVolumes, ...
    MinimumSupportFraction=options.MinimumSupportFraction, ...
    PenaltyPerMetre=options.PenaltyPerMetre, ...
    MaximumPenalty=options.MaximumPenalty, ...
    DirectionCount=options.DirectionCount);

reference = struct;
equivalence = struct("Performed", false, "Pass", false);
referenceSeconds = NaN;
netSpeedup = NaN;
if options.CompareCpu
    referenceTimer = tic;
    raw = d.runZnccOptimized(z, ...
        TileSize=options.TileSize, ...
        LabelBlockSize=options.LabelBlockSize, ...
        StoreCostVolumes=true, UseParallel=false, ...
        WorkingPrecision=options.WorkingPrecision, ...
        MinimumSupportFraction=options.MinimumSupportFraction, ...
        Products=["LabelIndex", "BestCost", "Margin"]);
    sgm = HeightSgm.aggregateVectorized(raw.CostVolume, z, ...
        PenaltyPerMetre=options.PenaltyPerMetre, ...
        MaximumPenalty=options.MaximumPenalty, ...
        DirectionCount=options.DirectionCount);
    referenceSeconds = toc(referenceTimer);
    rawComparison = HeightSweepEquivalence.compare( ...
        raw.CostVolume, q.CostVolume, ...
        CostTolerance=options.CostTolerance, ...
        TieTolerance=options.TieTolerance);
    sgmComparison = HeightSweepEquivalence.compare( ...
        sgm.AggregatedCost, q.AggregatedCost, ...
        CostTolerance=options.CostTolerance, ...
        TieTolerance=options.TieTolerance);
    selectionValidEqual = isequal(sgm.Valid, q.SgmSelectionValid);
    projectionValid = d.projectHeightMap( ...
        sgm.HeightMetres, sgm.Valid, ...
        Products=["Correspondence", "Observability"]);
    finalValidEqual = isequal(projectionValid.Valid, q.Valid);
    equivalence = struct( ...
        "Performed", true, ...
        "Pass", rawComparison.Pass && sgmComparison.Pass ...
        && selectionValidEqual && finalValidEqual, ...
        "RawZncc", rawComparison, ...
        "Sgm", sgmComparison, ...
        "SgmSelectionValidEqual", selectionValidEqual, ...
        "FinalProjectionValidEqual", finalValidEqual, ...
        "LabelIndexExactlyEqual", isequal(sgm.LabelIndex, q.LabelIndex), ...
        "Policy", ...
        "identical geometry/labels/masks/cost/SGM; bounded array delta");
    reference = struct( ...
        "RuntimeSeconds", referenceSeconds, ...
        "ZnccRuntimeSeconds", raw.Runtime.EvaluationSeconds, ...
        "SgmRuntimeSeconds", sgm.RuntimeSeconds, ...
        "Implementation", ...
        "optimized CPU array ZNCC plus vectorized CPU SGM");
    targetComparableSeconds = q.Runtime.TotalSeconds ...
        - q.Runtime.FinalCpuProjectionSeconds;
    netSpeedup = referenceSeconds ./ targetComparableSeconds;
end

rt = q.Runtime;
stage = table( ...
    ["render"; "prepare"; "source-transfer"; "cpu-geometry"; ...
    "zncc-array"; "sgm-array"; "output-transfer"; ...
    "final-cpu-projection"; "target-total"; "cpu-reference-total"], ...
    [renderSeconds; prepareSeconds; rt.SourceTransferSeconds; ...
    rt.CpuGeometrySeconds; rt.ZnccArrayKernelSeconds; ...
    rt.SgmArraySeconds; rt.OutputTransferSeconds; ...
    rt.FinalCpuProjectionSeconds; rt.TotalSeconds; referenceSeconds], ...
    VariableNames=["Stage", "Seconds"]);

deviceCount = gpuDeviceCount("available");
device = struct("AvailableDeviceCount", deviceCount, ...
    "Name", "not inspected", "AvailableMemoryBytes", 0, ...
    "ComputeCapability", "not inspected");
if deviceCount > 0
    index = options.DeviceIndex;
    if index == 0
        index = 1;
    end
    gd = gpuDevice(index);
    device.Name = string(gd.Name);
    device.AvailableMemoryBytes = double(gd.AvailableMemory);
    device.ComputeCapability = string(gd.ComputeCapability);
end
machine = struct( ...
    "MatlabRelease", string(version("-release")), ...
    "Computer", string(computer), ...
    "NativeCoreCount", feature("numcores"), ...
    "Gpu", device);

if ~options.StoreCostVolumes
    q.CostVolume = zeros([options.ImageSize, 0], ...
        options.WorkingPrecision);
    q.AggregatedCost = zeros([options.ImageSize, 0], ...
        options.WorkingPrecision);
    q.StoreCostVolumes = false;
end
report = struct( ...
    "Configuration", struct( ...
    "ExecutionTarget", options.ExecutionTarget, ...
    "ImageSize", options.ImageSize, ...
    "HeightLabelsMetres", z, ...
    "TileSize", options.TileSize, ...
    "LabelBlockSize", options.LabelBlockSize, ...
    "WorkingPrecision", options.WorkingPrecision, ...
    "DirectionCount", options.DirectionCount, ...
    "PenaltyPerMetre", options.PenaltyPerMetre, ...
    "MaximumPenalty", options.MaximumPenalty, ...
    "TextureSeed", options.TextureSeed), ...
    "Result", q, ...
    "Preflight", q.Preflight, ...
    "StageTiming", stage, ...
    "Transfer", struct( ...
    "SourceBytes", rt.SourceTransferBytes, ...
    "OutputBytes", rt.OutputTransferBytes, ...
    "DiagnosticVolumesTransferredForComparison", ...
    options.CompareCpu), ...
    "Throughput", struct( ...
    "PixelLabelsPerSecond", rt.PixelLabelsPerSecond, ...
    "PixelsPerSecond", rt.PixelCount ./ rt.TotalSeconds), ...
    "Performance", struct( ...
    "TargetComparableSeconds", rt.TotalSeconds ...
    - rt.FinalCpuProjectionSeconds, ...
    "CpuReferenceSeconds", referenceSeconds, ...
    "NetSpeedupVsCpu", netSpeedup, ...
    "Definition", ...
    "CPU ZNCC+SGM divided by target transfer+geometry+ZNCC+SGM+gather"), ...
    "EstimatedDevicePeakBytes", rt.EstimatedDevicePeakBytes, ...
    "EstimatedDevicePeakGiB", rt.EstimatedDevicePeakGiB, ...
    "DeviceMemorySamples", rt.DeviceMemorySamples, ...
    "SampledPeakDeviceBytes", rt.SampledPeakDeviceBytes, ...
    "SampledPeakDeviceGiB", rt.SampledPeakDeviceBytes ./ 2 ^ 30, ...
    "PreflightCoversSampledPeak", rt.PreflightCoversSampledPeak, ...
    "SampledPeakDefinition", rt.SampledPeakDefinition, ...
    "Equivalence", equivalence, ...
    "CpuReference", reference, ...
    "Machine", machine, ...
    "GeometryPrecision", "double", ...
    "ArrayLayout", "[row,column,label]", ...
    "InvalidPolicy", "explicit logical masks and NaN costs");

if options.Verbose
    fprintf("G1.3 height-sweep benchmark: %s, %d-by-%d, %d labels\n", ...
        options.ExecutionTarget, options.ImageSize(1), ...
        options.ImageSize(2), options.LabelCount);
    disp(stage);
    fprintf("Estimated device peak: %.3f GiB; throughput: %.3g " ...
        + "pixel-labels/s\n", report.EstimatedDevicePeakGiB, ...
        report.Throughput.PixelLabelsPerSecond);
    if isfinite(report.SampledPeakDeviceGiB)
        fprintf("Sampled device use lower bound: %.3f GiB; " ...
            + "preflight covers samples: %s\n", ...
            report.SampledPeakDeviceGiB, ...
            string(report.PreflightCoversSampledPeak));
        disp(report.DeviceMemorySamples);
    end
    fprintf("Transfers: %.3f MiB source, %.3f MiB output\n", ...
        report.Transfer.SourceBytes ./ 2 ^ 20, ...
        report.Transfer.OutputBytes ./ 2 ^ 20);
    if options.CompareCpu
        fprintf("CPU equivalence pass: %s\n", ...
            string(report.Equivalence.Pass));
        fprintf("Net speedup versus CPU: %.3fx\n", ...
            report.Performance.NetSpeedupVsCpu);
    end
end
if options.OutputFile ~= ""
    save(options.OutputFile, "report", "-v7.3");
end
end

function mustBeIncreasing(x)
if x(2) <= x(1)
    error("runGpuHeightSweepBenchmark:HeightRangeNotIncreasing", ...
        "HeightRangeMetres must be strictly increasing.");
end
end
